if (typeof msg.payload === 'object') {
    if (msg.payload.id !== 'abdellah') {
        node.status({ fill:'grey', shape:'ring', text:'Wrong id' });
        return null;
    }
    node.status({ fill:'green', shape:'dot', text:'abdellah OK' });
    return msg;
}

let line = '';
if (Buffer.isBuffer(msg.payload)) {
    line = msg.payload.toString('utf8').trim();
} else {
    line = String(msg.payload).trim();
}

if (!line) return null;

// Guard: catch the literal string '[object Object]' which means something
// upstream called String(obj) instead of JSON.stringify(obj)/serializeJson().
if (line === '[object Object]') {
    node.status({ fill:'red', shape:'ring', text:'Got [object Object] - upstream bug' });
    node.warn('Gateway: received literal "[object Object]" string - sender must use JSON.stringify()/serializeJson(), not String(obj).');
    return null;
}

const start = line.indexOf('{');
const end   = line.lastIndexOf('}');
if (start === -1 || end === -1) {
    node.status({ fill:'grey', shape:'ring', text:'Not JSON' });
    return null;
}
line = line.substring(start, end + 1);

let data;
try {
    data = JSON.parse(line);
} catch(err) {
    node.status({ fill:'red', shape:'ring', text:'Parse error' });
    return null;
}

if (data.id !== 'abdellah') {
    node.status({ fill:'grey', shape:'ring', text:'Wrong id' });
    return null;
}

msg.payload = data;
node.status({ fill:'green', shape:'dot', text:'abdellah OK' });
return msg;

// Normalizes/renames raw ESP32 fields into a clean, consistent JSON object
// and adds a gateway-side timestamp + gateway id for traceability.
// NOTE: percentage/ratio math here is unit normalization (mL/mV -> %, mS/cm),
// not irrigation decision logic - no thresholds or pump actions are decided here.

const d = msg.payload;

const pct_drainage = parseFloat(d.input_mL) > 0
    ? parseFloat(((parseFloat(d.drainage_mL || 0) / parseFloat(d.input_mL)) * 100).toFixed(1))
    : 0;

const ec_mscm = parseFloat((parseFloat(d.ec_drainage || 0) / 1000).toFixed(2));
const ph      = parseFloat(parseFloat(d.ph || 0).toFixed(2));

msg.payload = {
    id:            d.id || 'abdellah',
    weight_g:      parseFloat(d.weight_g)      || 0,
    pct_drainage:  pct_drainage,
    ec_mscm:       ec_mscm,
    ph:            ph,
    input_mL:      parseFloat(d.input_mL)      || 0,
    drainage_mL:   parseFloat(d.drainage_mL)   || 0,
    water_used_mL: parseFloat(d.water_used_mL) || 0,
    temp:          parseFloat(d.temp_drainage)  || 0,
    soil_pct:      parseFloat(d.soil_pct)       || 0,
    pump:          d.pump       || 'OFF',
    drain_pump:    d.drain_pump || 'OFF',
    timestamp:     d.timestamp || new Date().toISOString(),
    gateway:       'raspberry01'
};

msg.topic = 'irrigation/abdellah/data';

node.status({ fill:'blue', shape:'dot',
    text: `drain:${pct_drainage}% EC:${ec_mscm} pH:${ph} w:${d.weight_g}g` });

return msg;

// Queue for topic irrigation/abdellah/data
const queue = flow.get('gw_outbox_data') || [];
const MAX_QUEUE = 500; // cap to avoid unbounded memory growth

queue.push({ topic: msg.topic, payload: msg.payload, qos: 1, retain: false });

if (queue.length > MAX_QUEUE) {
    queue.shift(); // drop oldest if over capacity
    node.warn('Sensor data outbox overflow - oldest message dropped');
}

flow.set('gw_outbox_data', queue);
node.status({ fill:'blue', shape:'dot', text:`Queued | size=${queue.length}` });

return { _flushTrigger: true };

// Attempts to send queued messages in order if the MQTT connection is up.
const queue = flow.get('gw_outbox_data') || [];

if (queue.length === 0) {
    node.status({ fill:'grey', shape:'ring', text:'Outbox empty' });
    return null;
}

let connected = true;
try {
    const brokerNode = RED.nodes.getNode('gw_mqtt_broker_cfg');
    if (brokerNode && typeof brokerNode.connected !== 'undefined') {
        connected = brokerNode.connected;
    }
} catch (e) {
    connected = true;
}

if (!connected) {
    node.status({ fill:'red', shape:'ring', text:`Offline | buffered=${queue.length}` });
    return null;
}

const toSend = queue.splice(0, queue.length);
flow.set('gw_outbox_data', queue);

node.status({ fill:'green', shape:'dot', text:`Flushed ${toSend.length} msg(s)` });

// payload kept as a real object so mqtt out serializes proper JSON
const msgs = toSend.map(item => ({
    topic:   item.topic,
    payload: item.payload,
    qos:     item.qos,
    retain:  item.retain
}));

return [msgs];

// Basic structural validation only - NO interpretation of command meaning.
// Ensures payload is valid JSON and contains an 'id' field, then
// serializes it into the line format expected by the ESP32 over LoRa.

let cmd;

if (typeof msg.payload === 'string') {
    try {
        cmd = JSON.parse(msg.payload);
    } catch (err) {
        node.status({ fill:'red', shape:'ring', text:'Invalid JSON from MQTT' });
        node.warn('Gateway: received invalid JSON command on ' + msg.topic + ': ' + msg.payload);
        return null;
    }
} else if (typeof msg.payload === 'object' && msg.payload !== null) {
    cmd = msg.payload;
} else {
    node.status({ fill:'red', shape:'ring', text:'Unsupported payload type' });
    return null;
}

if (!cmd.id) {
    node.status({ fill:'red', shape:'ring', text:'Missing id field' });
    node.warn('Gateway: command missing "id" field, dropping: ' + JSON.stringify(cmd));
    return null;
}

// Serialize to single-line JSON for LoRa transmission
msg.payload = JSON.stringify(cmd) + '\n';

node.status({ fill:'green', shape:'dot', text:'CMD -> LoRa: ' + cmd.id });
return msg;

// Purely informational status message - no logic, no decisions.
const nowMs = Date.now();
const startMs = flow.get('gw_start_time') || (() => {
    flow.set('gw_start_time', nowMs);
    return nowMs;
})();

const uptimeSec = Math.floor((nowMs - startMs) / 1000);

const h = Math.floor(uptimeSec / 3600);
const m = Math.floor((uptimeSec % 3600) / 60);
const s = uptimeSec % 60;
const uptimeStr = `${h}h ${m}m ${s}s`;

msg.topic = 'irrigation/rpi/raspStatus';
msg.payload = {
    gateway:   'raspberry01',
    online:    true,
    uptime:    uptimeStr,
    uptime_s:  uptimeSec,
    last_seen: new Date().toISOString()
};

node.status({ fill:'green', shape:'dot', text:`Heartbeat sent | up ${uptimeStr}` });
return msg;

// Queue for topic irrigation/rpi/raspStatus
// Keep only the latest heartbeat to avoid stale uptime spam after reconnect.
const queue = flow.get('gw_outbox_status') || [];

queue.length = 0; // always keep just the freshest heartbeat
queue.push({ topic: msg.topic, payload: msg.payload, qos: 1, retain: true });

flow.set('gw_outbox_status', queue);
node.status({ fill:'blue', shape:'dot', text:`Queued (heartbeat) | size=${queue.length}` });

return { _flushTrigger: true };

const queue = flow.get('gw_outbox_status') || [];

if (queue.length === 0) {
    node.status({ fill:'grey', shape:'ring', text:'Outbox empty' });
    return null;
}

let connected = true;
try {
    const brokerNode = RED.nodes.getNode('gw_mqtt_broker_cfg');
    if (brokerNode && typeof brokerNode.connected !== 'undefined') {
        connected = brokerNode.connected;
    }
} catch (e) {
    connected = true;
}

if (!connected) {
    node.status({ fill:'red', shape:'ring', text:`Offline | buffered=${queue.length}` });
    return null;
}

const toSend = queue.splice(0, queue.length);
flow.set('gw_outbox_status', queue);

node.status({ fill:'green', shape:'dot', text:`Flushed ${toSend.length} msg(s)` });

const msgs = toSend.map(item => ({
    topic:   item.topic,
    payload: item.payload,
    qos:     item.qos,
    retain:  item.retain
}));

return [msgs];

msg.topic = 'irrigation/rpi/error';
msg.payload = {
    gateway:   'raspberry01',
    error:     msg.error ? msg.error.message : 'Unknown error',
    source:    (msg.error && msg.error.source) ? msg.error.source.id : null,
    timestamp: new Date().toISOString()
};
node.warn('Gateway error: ' + JSON.stringify(msg.payload));
return msg;
